import json
import pickle
import boto3
import os

def lambda_handler(event, context):
    # Validate and parse the incoming event
    if 'body' not in event:
        return {'statusCode': 400, 'body': 'Invalid request: No body found'}
    
    try:
        payload = json.loads(event['body'])
    except json.JSONDecodeError:
        return {'statusCode': 400, 'body': 'Invalid JSON format'}

    # Validate payload structure
    if 'action' not in payload or 'data' not in payload:
        return {'statusCode': 400, 'body': 'Invalid payload structure'}

    # Example of action allowlist
    allowed_actions = ['create', 'update', 'delete']
    if payload['action'] not in allowed_actions:
        return {'statusCode': 403, 'body': 'Action not allowed'}

    # Process the action securely
    try:
        # Deserialize the data using pickle
        # Ensure that the data is from a trusted source before deserializing
        user_action_data = pickle.loads(payload['data'].encode('utf-8'))
        
        # Process the action (example: log the action)
        # Ensure sensitive data is not logged
        print(f"Processing action: {payload['action']} for user: {user_action_data.get('user_id', 'unknown')}")

        # Example of using AWS SDK securely
        # Assume the role with least privilege
        sts_client = boto3.client('sts')
        assumed_role = sts_client.assume_role(
            RoleArn=os.environ['ROLE_ARN'],
            RoleSessionName='WebhookProcessingSession'
        )
        credentials = assumed_role['Credentials']
        
        # Use the temporary credentials to perform AWS operations
        # Example: store processed data in S3
        s3_client = boto3.client(
            's3',
            aws_access_key_id=credentials['AccessKeyId'],
            aws_secret_access_key=credentials['SecretAccessKey'],
            aws_session_token=credentials['SessionToken']
        )
        s3_client.put_object(
            Bucket=os.environ['S3_BUCKET'],
            Key=f"user_actions/{user_action_data.get('user_id', 'unknown')}.pkl",
            Body=pickle.dumps(user_action_data)
        )
        
        return {'statusCode': 200, 'body': 'Action processed successfully'}
    
    except Exception as e:
        # Log the error securely
        print(f"Error processing action: {str(e)}")
        return {'statusCode': 500, 'body': 'Internal server error'}